struct Info {
	Info() :siz(0) {};
	Info(int siz) :siz(siz) {};

	// 要维护的值
	int siz;
	void apply(const Info& v) {
		// 如何单点修改
		siz += v.siz;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.siz = a.siz + b.siz;
	return c;
}
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	string a; cin >> a; a = ' ' + a;
	var init = vector<Info>(n + 1);
	fa(i, 1, n)init[i].siz = 1;
	var seg = SegmentTree<Info>(init);
	var se = vector<set<int>>(80);
	fa(i, 1, n)se[a[i] - '0'].insert(i);
	while (m--) {
		int l, r; cin >> l >> r;
		char x; cin >> x; x -= '0';
		int L = seg.findl(l), R = seg.findl(r); // 使用线段树二分，把动态下标转成原始下标
		var it = se[x].lower_bound(L);
		while (it != se[x].end() and *it <= R) {
			seg.modify(*it, -1);
			it = se[x].erase(it);
		}
	}
	fa(i, 1, n) {
		int mn = INF, id = INF;
